// Serializar payload para el LLM — incluye datos matemáticos para clasificación
return items.map(item => {
  const src = item.json || {};

  const getStr = (...keys) => {
    for (const k of keys) {
      if (src[k] !== undefined && src[k] !== null) return String(src[k]);
    }
    return '';
  };

  const match = getStr('Match', 'match');
  const league = getStr('League', 'league');
  const country = getStr('Country', 'country');
  const timestamp = getStr('timestamp') || new Date().toISOString();

  const bestSrc = src.best || {};

  // Contar casas distintas involucradas
  const casas = new Set([
    bestSrc?.home?.bookmaker,
    bestSrc?.draw?.bookmaker,
    bestSrc?.away?.bookmaker
  ].filter(Boolean));

  const normalized = {
    match, league, country, timestamp,
    horasRestantes: src.horasRestantes ?? null,
    // Datos matemáticos clave para el clasificador
    margen: src.margen ?? null,
    beneficioPct: src.beneficioPct ?? 0,
    surebet: src.surebet ?? false,
    casasDistintas: casas.size,
    best: {
      home: { odds: bestSrc?.home?.odds ?? null, bookmaker: bestSrc?.home?.bookmaker ?? null },
      draw: { odds: bestSrc?.draw?.odds ?? null, bookmaker: bestSrc?.draw?.bookmaker ?? null },
      away: { odds: bestSrc?.away?.odds ?? null, bookmaker: bestSrc?.away?.bookmaker ?? null }
    }
  };

  const hasOdds = normalized.best.home.odds
    && normalized.best.draw.odds
    && normalized.best.away.odds;

  return {
    json: {
      ...src,
      normalized,
      payloadString: JSON.stringify(normalized),
      skipLLM: !hasOdds
    }
  };
});

