// Parsear salida LLM y mergear con datos del partido
// Opción A: LLM es clasificador puro, no devuelve prob
return items.map(item => {
  const rawCandidate =
    item.json?.text ||
    item.json?.response ||
    item.json?.choices?.[0]?.message?.content ||
    null;

  let parsed = null;
  if (rawCandidate) {
    let cleanStr = typeof rawCandidate === 'string'
      ? rawCandidate.trim()
      : JSON.stringify(rawCandidate);
    cleanStr = cleanStr.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
    try {
      parsed = JSON.parse(cleanStr);
    } catch (e) {
      try {
        const m = cleanStr.match(/\{[\s\S]*\}/);
        parsed = m ? JSON.parse(m[0]) : null;
      } catch (e2) { parsed = null; }
    }
  }

  const llm = {
    tipo:      parsed?.tipo      || 'ninguno',
    riesgo:    parsed?.riesgo    || 'alto',
    confianza: Number(parsed?.confianza ?? 0),
    comentario: parsed?.comentario || 'LLM sin respuesta válida',
    raw: rawCandidate || null
  };

  const src = item.json?.src || item.json || {};

  return {
    json: {
      match:        src.match        || null,
      best:         src.best         || null,
      league:       src.league       || null,
      country:      src.country      || null,
      region:       src.region       || null,
      horasRestantes: src.horasRestantes ?? null,
      surebet:      src.surebet      || false,
      beneficioPct: src.beneficioPct || 0,
      margen:       src.margen       || null,
      stakes:       src.stakes       || null,
      capitalTotal: src.capitalTotal || 100,
      currencies:   src.currencies   || { home: 'PEN', draw: 'PEN', away: 'PEN' },
      tipo:      llm.tipo,
      riesgo:    llm.riesgo,
      confianza: llm.confianza,
      comentario: llm.comentario
    }
  };
});

// ValueCalc — Opción A
// Probabilidades implícitas derivadas matemáticamente de las cuotas
// NO se usan probabilidades del LLM
const threshold = Number($('CONFIG').first().json.CFG_VALUE_THRESHOLD ?? 1.05);

return items.map(item => {
  const { match, best, stakes, beneficioPct, capitalTotal, currencies, surebet,
          tipo, riesgo, confianza, comentario, league, country, region,
          horasRestantes, margen } = item.json;

  // Probabilidades implícitas normalizadas (eliminan el margen de la casa)
  const oHome = best?.home?.odds || 0;
  const oDraw = best?.draw?.odds || 0;
  const oAway = best?.away?.odds || 0;

  const invSum = (oHome > 0 ? 1/oHome : 0)
               + (oDraw > 0 ? 1/oDraw : 0)
               + (oAway > 0 ? 1/oAway : 0);

  const prob = invSum > 0 ? {
    local:     (1/oHome) / invSum,
    empate:    (1/oDraw) / invSum,
    visitante: (1/oAway) / invSum
  } : { local: 0.33, empate: 0.33, visitante: 0.34 };

  // Valor esperado por resultado
  const valHome = prob.local     * oHome;
  const valDraw = prob.empate    * oDraw;
  const valAway = prob.visitante * oAway;

  const valueBets = [];
  if (valHome > threshold) valueBets.push({
    outcome: 'home', label: 'Local',
    valor: valHome,
    roi: ((valHome - 1) * 100).toFixed(2),
    bookmaker: best?.home?.bookmaker,
    cuota: best?.home?.odds
  });
  if (valDraw > threshold) valueBets.push({
    outcome: 'draw', label: 'Empate',
    valor: valDraw,
    roi: ((valDraw - 1) * 100).toFixed(2),
    bookmaker: best?.draw?.bookmaker,
    cuota: best?.draw?.odds
  });
  if (valAway > threshold) valueBets.push({
    outcome: 'away', label: 'Visitante',
    valor: valAway,
    roi: ((valAway - 1) * 100).toFixed(2),
    bookmaker: best?.away?.bookmaker,
    cuota: best?.away?.odds
  });

  return {
    json: {
      match, best, league, country, region, horasRestantes, margen,
      prob, valueBets, surebet,
      tipo, riesgo, confianza, comentario,
      stakes, capitalTotal, currencies,
      beneficioPct,
      roiPct: valueBets.map(v => v.roi)
    }
  };
});

// Formatear todos los campos para presentación
return items.map(item => {
  const out = { ...item.json };

  // Beneficio formateado
  out.beneficioPctFmt = out.beneficioPct !== undefined
    ? `${Number(out.beneficioPct).toFixed(2)}%`
    : '0.00%';

  // Stakes formateados con moneda correcta
  if (out.stakes && out.currencies) {
    out.stakesRounded = {
      home: Number(out.stakes.home).toFixed(2),
      draw: Number(out.stakes.draw).toFixed(2),
      away: Number(out.stakes.away).toFixed(2)
    };
  } else {
    out.stakesRounded = { home: '0.00', draw: '0.00', away: '0.00' };
  }

  // Cuotas formateadas
  if (out.best) {
    out.bestFmt = {
      home: `${out.best.home?.odds ?? '-'} (${out.best.home?.bookmaker ?? '-'})`,
      draw: `${out.best.draw?.odds ?? '-'} (${out.best.draw?.bookmaker ?? '-'})`,
      away: `${out.best.away?.odds ?? '-'} (${out.best.away?.bookmaker ?? '-'})`
    };
  }

  // Etiqueta de tipo para el mensaje
  const tipoLabel = out.tipo === 'surebet' ? '🔒 Surebet'
    : out.tipo === 'valuebet' ? '📈 Value Bet'
    : '⚪ Sin oportunidad';
  out.tipoLabel = tipoLabel;

  // Liga y país formateados
  out.ligaFmt = [out.league, out.country].filter(Boolean).join(' · ') || 'Liga desconocida';

  // Value bets summary
  out.valueBetsFmt = (out.valueBets || []).length > 0
    ? out.valueBets.map(v => `${v.label}: cuota ${v.cuota} en ${v.bookmaker} (ROI +${v.roi}%)`).join('\n')
    : null;

  return { json: out };
});

// Filtrar partidos cuyo inicio supera CFG_MAX_HORAS_AL_PARTIDO
const cfg = $('CONFIG').first().json;
const maxHoras = cfg.CFG_MAX_HORAS_AL_PARTIDO ?? 48;

return items.filter(item => {
  const ts = item.json.timestamp;
  if (!ts) return true; // si no hay timestamp, dejar pasar

  const matchTime = new Date(ts).getTime();
  const now = Date.now();

  // Si el partido ya empezó, descartar
  if (matchTime <= now) return false;

  const horasRestantes = (matchTime - now) / (1000 * 60 * 60);
  return horasRestantes <= maxHoras;
}).map(item => ({
  json: {
    ...item.json,
    horasRestantes: parseFloat(
      ((new Date(item.json.timestamp).getTime() - Date.now()) / (1000 * 60 * 60)).toFixed(1)
    )
  }
}));

// Análisis estadístico de casas de apuestas
// Cuenta cuántas veces cada casa ofrece la mejor cuota por resultado
const raw = items[0].json;
const events = raw.events || [];

const ranking = {}; // { bookmaker: { home: N, draw: N, away: N, total: N } }
let totalPartidos = 0;
let totalOffers = 0;

events.forEach(e => {
  const bookmakers = e.canonical?.bookmakers || {};
  const bkList = Object.keys(bookmakers);
  if (bkList.length === 0) return;

  totalPartidos++;

  // Encontrar mejor cuota por resultado en este partido
  let bestHome = { bk: null, odds: -1 };
  let bestDraw = { bk: null, odds: -1 };
  let bestAway = { bk: null, odds: -1 };

  bkList.forEach(bk => {
    totalOffers++;
    const odds = bookmakers[bk].odds || {};
    const ox = odds['1X2'] || odds['1x2'] || null;
    if (!ox) return;

    if (!ranking[bk]) ranking[bk] = { home: 0, draw: 0, away: 0, total: 0, partidos: 0 };
    ranking[bk].partidos++;

    if (ox[0] > bestHome.odds) bestHome = { bk, odds: ox[0] };
    if (ox[1] > bestDraw.odds) bestDraw = { bk, odds: ox[1] };
    if (ox[2] > bestAway.odds) bestAway = { bk, odds: ox[2] };
  });

  // Sumar wins al ranking
  if (bestHome.bk) { ranking[bestHome.bk].home++; ranking[bestHome.bk].total++; }
  if (bestDraw.bk) { ranking[bestDraw.bk].draw++; ranking[bestDraw.bk].total++; }
  if (bestAway.bk) { ranking[bestAway.bk].away++; ranking[bestAway.bk].total++; }
});

// Ordenar por total de veces con mejor cuota
const sorted = Object.entries(ranking)
  .map(([bk, s]) => ({
    bookmaker: bk,
    total: s.total,
    home: s.home,
    draw: s.draw,
    away: s.away,
    partidos: s.partidos,
    pctMejorCuota: totalPartidos > 0
      ? ((s.total / (totalPartidos * 3)) * 100).toFixed(1)
      : '0.0'
  }))
  .sort((a, b) => b.total - a.total);

// Construir mensaje Telegram
const top10 = sorted.slice(0, 10);
const fecha = new Date().toLocaleDateString('es-PE', {
  timeZone: 'America/Lima',
  day: '2-digit', month: '2-digit', year: 'numeric'
});

let msg = `🏆 Ranking de Casas — ${fecha}\n`;
msg += `📊 ${totalPartidos} partidos analizados\n\n`;

top10.forEach((c, i) => {
  const medal = i === 0 ? '🥇' : i === 1 ? '🥈' : i === 2 ? '🥉' : `${i+1}.`;
  msg += `${medal} ${c.bookmaker}\n`;
  msg += `   Mejor cuota ${c.pctMejorCuota}% del tiempo\n`;
  msg += `   🏠${c.home} 🤝${c.draw} ✈️${c.away}\n`;
});

msg += `\n💡 Abrir cuenta primero en: ${top10.slice(0,3).map(c => c.bookmaker).join(', ')}`;

return [{ json: { rankingMsg: msg, ranking: sorted, totalPartidos } }];
